```java
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Solution {

    static class RangeInfo {
        long orVal;
        int startIndex; // The earliest start index i such that OR(i, j) = orVal

        public RangeInfo(long orVal, int startIndex) {
            this.orVal = orVal;
            this.startIndex = startIndex;
        }
    }

    public static long solve(long[] nums) {
        int n = nums.length;
        long totalGoodSubarrays = 0;

        // orRangesJ holds the distinct OR values achievable by subarrays ending at j,
        // represented by {orVal, startIndex}. It is sorted by startIndex descending.
        List<RangeInfo> orRangesJ = new ArrayList<>();

        for (int j = 0; j < n; j++) {
            List<RangeInfo> newRanges = new ArrayList<>();

            // 1. Subarray [j, j]
            long valJ = nums[j];
            newRanges.add(new RangeInfo(valJ, j));

            // 2. Extend all ranges from j-1
            for (RangeInfo range : orRangesJ) {
                long newOr = range.orVal | valJ;
                newRanges.add(new RangeInfo(newOr, range.startIndex));
            }

            // 3. Consolidate ranges: Group by OR_val and keep the smallest start_index for each.
            Map<Long, Integer> mergedMap = new HashMap<>(); // OR_val -> smallest_start_index

            for (RangeInfo range : newRanges) {
                long orVal = range.orVal;
                int startIndex = range.startIndex;
                if (!mergedMap.containsKey(orVal) || startIndex < mergedMap.get(orVal)) {
                    mergedMap.put(orVal, startIndex);
                }
            }

            // Convert map to a list and sort by start_index descending
            List<RangeInfo> consolidatedRanges = new ArrayList<>();
            for (Map.Entry<Long, Integer> entry : mergedMap.entrySet()) {
                consolidatedRanges.add(new RangeInfo(entry.getKey(), entry.getValue()));
            }
            // Sort descending by startIndex to easily define ranges [i_k, i_{k-1}-1]
            consolidatedRanges.sort((a, b) -> Integer.compare(b.startIndex, a.startIndex));

            orRangesJ = consolidatedRanges;

            // 4. Calculate good subarrays ending at j
            int currentStartIndex = j + 1; // The index *after* the range ends

            for (RangeInfo rangeInfo : orRangesJ) {
                long Ok = rangeInfo.orVal;
                int ik = rangeInfo.startIndex; // The earliest start index that results in Ok

                // The range of starting indices [i, j] that results in Ok is [ik, currentStartIndex - 1].
                int startRangeStart = ik;
                int startRangeEnd = currentStartIndex - 1;

                if (startRangeEnd < startRangeStart) {
                    // Should not happen if consolidation is correct, but safe check
                    currentStartIndex = ik;
                    continue;
                }

                // Find the largest index R <= j such that nums[R] == Ok.
                int R = -1;
                for (int r = j; r >= startRangeStart; r--) {
                    if (nums[r] == Ok) {
                        R = r;
                        break;
                    }
                }

                if (R != -1) {
                    // All starting indices i such that i <= R will result in a good subarray [i...j] containing Ok.
                    // We count how many such i are in the range [startRangeStart, startRangeEnd].

                    // The valid starting indices i are in [startRangeStart, startRangeEnd] AND i <= R.
                    int countGoodForThisOr = Math.min(R, startRangeEnd) - startRangeStart + 1;

                    if (countGoodForThisOr > 0) {
                        totalGoodSubarrays += countGoodForThisOr;
                    }
                }

                // Update for next iteration
                currentStartIndex = ik;
            }
        }

        return totalGoodSubarrays;
    }
}
