public class Solution {
    // Helper class to store OR value and its earliest starting index
    private static class RangeInfo {
        long orVal;
        int startIndex;

        RangeInfo(long orVal, int startIndex) {
            this.orVal = orVal;
            this.startIndex = startIndex;
        }
    }

    public static long solve(long[] nums) {
        int n = nums.length;
