        // R_m = [i_m, i_{m-1} - 1] yielding OR_m. (Where i_m is the start_index stored).
        // R_1 = [0, i_2 - 1] yielding OR_1.

        // We need to reconstruct the actual ranges [start_index_k, start_index_{k-1}-1]

        let current_start_index = j + 1; // The index *after* the range ends
        let prev_or_val = -1;

        // We iterate through the consolidated list (which is sorted by start_index descending, so i_m is the start_index)
        for (let k = 0; k < or_ranges_j_minus_1.length; k++) {
            const range_info = or_ranges_j_minus_1[k];
            const O_k = range_info.or_val;
            const i_k = range_info.start_index; // This is the earliest start index that results in O_k

            // The range of starting indices [i, j] that results in O_k is [i_k, current_start_index - 1].
            const start_range_start = i_k;
            const start_range_end = current_start_index - 1;
            const range_length = start_range_end - start_range_start + 1;

            if (range_length > 0) {
                // For any i in [start_range_start, start_range_end], OR(i, j) = O_k.
                // We check the good subarray condition for O_k: Is O_k present in nums[i...j]?

                // Since O_k is the OR sum of nums[i...j], the condition is met IF AND ONLY IF
                // there exists k' in [i, j] such that nums[k'] = O_k.

                // If O_k is present in nums[start_range_start...j], then it is present in all subarrays [i...j] where i is small enough.
                // The check needs to be: Is O_k present in nums[i...j] for *all* i in [start_range_start, start_range_end]? No, it needs to be present for *at least one* i.

                // The definition is: Subarray nums[i...j] is good if OR(i,j) is present in nums[i...j].
                // For a fixed O_k, we need to count how many i in [start_range_start, start_range_end] satisfy:
                // O_k is in {nums[i], ..., nums[j]}.

                // This still requires iterating over the range of i, which defeats the O(N log C) goal if the range is large.

                // Observation 2: If O_k is present anywhere in nums[start_range_start...j], it is present in the subarray [start_range_start...j] (i.e., i=start_range_start).
                // If O_k is present in nums[start_range_end...j], it is present in [start_range_end...j] (i.e., i=start_range_end).

                // If O_k is present in nums[i...j], then for any i' < i, O_k is also present in nums[i'...j].
                // This is because nums[i...j] is a suffix of nums[i'...j], and if O_k is there, it remains there.

                // So, we just need to find the smallest i_min in [start_range_start, start_range_end] such that O_k is present in nums[i_min...j].
                // If such an i_min exists, then all i in [i_min, start_range_end] form good subarrays.

                // Let's find the rightmost occurrence of O_k in nums[0...j]. Let this be R.
                // If R >= start_range_start, then O_k is present in nums[start_range_start...j].
                // Since we are interested in the range [start_range_start, start_range_end], if R >= start_range_start, then O_k is present in *at least* one subarray corresponding to this OR value block.

                // This is still wrong. We need existence for *each* i in the range.
                // If O_k is present at index R, then for any i <= R, the subarray [i...j] contains O_k.
                // We need to count i in [start_range_start, start_range_end] such that i <= R.

                // Find the largest index R <= j such that nums[R] == O_k.
                let R = -1;
                for (let r = j; r >= start_range_start; r--) {
                    if (nums[r] === O_k) {
                        R = r;
                        break;
                    }
                }

                if (R !== -1) {
                    // All starting indices i such that i <= R will result in a good subarray [i...j].
                    // We count how many such i are in the range [start_range_start, start_range_end].
                    const count_good_for_this_or = Math.min(R, start_range_end) - start_range_start + 1;
                    if (count_good_for_this_or > 0) {
                        totalGoodSubarrays += count_good_for_this_or;
                    }
                }
            }

            // Update for next iteration
            prev_or_val = O_k;
            current_start_index = i_k;
        }
    }

    return totalGoodSubarrays;
}
